                {
                  "type": "listItem",
                  "content": [{ "type": "paragraph", "content": [{ "type": "text", "text": "Массив — объект: заголовок (тип, длина, служебные поля GC) + подряд элементы." }] }]
                },
                {
                  "type": "listItem",
                  "content": [{ "type": "paragraph", "content": [{ "type": "text", "text": "Массив примитивов — плотные значения; массив ссылок — плотные ссылки, объекты отдельно." }] }]
                }
              ]
            }
          ]
        },

        {
          "type": "listItem",
          "content": [
            {
              "type": "paragraph",
