                },
                {
                  "type": "listItem",
                  "content": [{ "type": "paragraph", "content": [{ "type": "text", "text": "TypedArray (Uint8Array, Float64Array и т.д.) — плотный ArrayBuffer, элементы фиксированного размера." }] }]
                }
              ]
            }
          ]
        },

        {
          "type": "listItem",
          "content": [
            {
