                {
                  "type": "listItem",
                  "content": [{ "type": "paragraph", "content": [{ "type": "text", "text": "Array — плотный фиксированный блок; Slice — дескриптор {ptr,len,cap} к массиву." }] }]
                }
              ]
            }
          ]
        },

