            },
            {
              "type": "bulletList",
              "content": [
                {
                  "type": "listItem",
                  "content": [{ "type": "paragraph", "content": [{ "type": "text", "text": "[T; N] — плотный; Vec<T> — {ptr,len,cap} + буфер; &[T] — срез над плотным участком." }] }]
                }
              ]
            }
          ]
        }
      ]
    },

    {
      "type": "heading",
      "attrs": { "level": 3 },
      "content": [{ "type": "text", "text": "Кэш, локальность и производительность" }]
    },
    {
      "type": "bulletList",
