        {
          "type": "text",
          "text": "import numpy as np\n# Плотный буфер с известными strides\nb = np.array([10, 20, 30], dtype=np.int32)\nprint(\"itemsize=\", b.itemsize, \"strides=\", b.strides)  # (4,) для int32\nprint(\"data ptr=\", b.__array_interface__['data'][0])     # адрес базового буфера\n\n# Обычный список Python — массив указателей (не плотные значения)\na = [10, 20, 30]\nprint([id(x) for x in a])  # адреса отдельных PyObject, разбросаны в куче\n"
        }
      ]
