      "type": "bulletList",
      "content": [
        {
          "type": "listItem",
          "content": [
            { "type": "paragraph", "content": [{ "type": "text", "text": "Перевыделение: при росте динамического массива старые указатели/итераторы могут стать недействительными." }] }
          ]
        },
        {
          "type": "listItem",
          "content": [
