          ]
        },
        {
          "type": "listItem",
          "content": [
            { "type": "paragraph", "content": [{ "type": "text", "text": "Выравнивание и sizeof: у структур возможны внутренние паддинги; stride = sizeof(struct)." }] }
          ]
        }
      ]
    }
  ]
