console.timeEnd('splice middle');"}]},{"type":"paragraph","content":[{"type":"text","text":"Ожидаемо: push работает заметно быстрее, чем unshift/splice, потому что не требует массовых сдвигов."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Практические выводы для web‑разработчика"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Для очередей и стэков используйте операции, работающие с концом массива: push/pop — самые дешёвые."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Если часто нужен «первый элемент», избегайте частых unshift/shift. Лучше используйте двустороннюю очередь (deque) на двух стеках:"}]}]}]},{"type":"codeBlock","content":[{"type":"text","text":"class Deque {
  constructor() { this.left = []; this.right = []; }
  pushBack(x) { this.right.push(x); }
  pushFront(x) { this.left.push(x); }
  popFront() {
    if (!this.left.length) while (this.right.length) this.left.push(this.right.pop());
    return this.left.pop();
  }
  popBack() {
    if (!this.right.length) while (this.left.length) this.right.push(this.left.pop());
    return this.right.pop();
  }
}

