        { "type": "listItem", "content": [{ "type": "paragraph", "content": [{ "type": "text", "text": "Нужен быстрый случайный доступ по индексу." }] }] },
        { "type": "listItem", "content": [{ "type": "paragraph", "content": [{ "type": "text", "text": "Требуется хорошая производительность при итерации (локальность данных)." }] }] }
      ]
    },
    {
      "type": "heading",
