{"type":"doc","content":[{"type":"heading","attrs":{"textAlign":null,"level":2},"content":[{"type":"text","text":"🧩 1. Алгоритм “двух указателей”"}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","marks":[{"type":"bold"}],"text":"Идея:"},{"type":"hardBreak"},{"type":"text","text":"Поменять местами элементы с начала и конца массива, постепенно двигаясь к центру."}]},{"type":"codeBlock","attrs":{"language":"javascript"},"content":[{"type":"text","text":"function reverseArray(arr) {
  let left = 0
  let right = arr.length - 1

  while (left < right) {
    // Меняем местами arr[left] и arr[right]
    const temp = arr[left]
    arr[left] = arr[right]
    arr[right] = temp

    left++
    right--
  }

  return arr
}

