      "content": [
        {
          "type": "text",
          "text": "function twoSumSorted(nums: number[], target: number): [number, number] | null {\n  let l = 0, r = nums.length - 1;\n  while (l < r) {\n    const sum = nums[l] + nums[r];\n    if (sum === target) return [l, r];\n    if (sum < target) l++; else r--;\n  }\n  return null;\n}\n\n// Пример: twoSumSorted([1,2,4,7,11,15], 15) -> [1,4] (2 + 13? нет; корректный ввод: [1,2,4,6,8,11,15], 15 -> [1,5] 2+13 не существует)\n// Важно: массив должен быть отсортирован."
        }
