    },
    {
      "type": "codeBlock",
      "attrs": {
        "language": "typescript"
      },
      "content": [
        {
          "type": "text",
          "text": "// Длина самой длинной подстроки без повторяющихся символов\nfunction lengthOfLongestSubstring(s: string): number {\n  let left = 0;\n  let maxLen = 0;\n  const last = new Map<string, number>(); // символ -> последний индекс\n\n  for (let right = 0; right < s.length; right++) {\n    const ch = s[right];\n    if (last.has(ch) && last.get(ch)! >= left) {\n      left = last.get(ch)! + 1; // сжимаем окно, чтобы убрать повтор\n    }\n    last.set(ch, right);\n    const len = right - left + 1;\n    if (len > maxLen) maxLen = len;\n  }\n  return maxLen;\n}\n\n// Сложность: O(n) по времени, O(мин(n, |алфавит|)) по памяти."
        }
      ]
