    {
      "type": "codeBlock",
      "attrs": {
        "language": "typescript"
      },
      "content": [
        {
          "type": "text",
          "text": "function mergeSorted(a: number[], b: number[]): number[] {\n  const res: number[] = [];\n  let i = 0, j = 0;\n  while (i < a.length && j < b.length) {\n    if (a[i] <= b[j]) res.push(a[i++]);\n    else res.push(b[j++]);\n  }\n  while (i < a.length) res.push(a[i++]);\n  while (j < b.length) res.push(b[j++]);\n  return res;\n}\n\n// Сложность: O(n + m) по времени, O(n + m) по памяти для результата (или O(1) при слиянии in-place с дополнительными условиями)."
        }
