    {
      "type": "codeBlock",
      "attrs": {
        "language": "typescript"
      },
      "content": [
        {
          "type": "text",
          "text": "// Удаление дубликатов из отсортированного массива (возвращает новую длину)\nfunction removeDuplicates(nums: number[]): number {\n  if (nums.length === 0) return 0;\n  let write = 1; // позиция для записи следующего уникального\n  for (let read = 1; read < nums.length; read++) {\n    if (nums[read] !== nums[read - 1]) {\n      nums[write++] = nums[read];\n    }\n  }\n  return write;\n}\n\n// Разворот массива in-place\nfunction reverseInPlace<T>(arr: T[]): void {\n  let l = 0, r = arr.length - 1;\n  while (l < r) {\n    [arr[l], arr[r]] = [arr[r], arr[l]];\n    l++; r--;\n  }\n}\n\n// Обе задачи используют два указателя и работают за O(n) времени и O(1) памяти."
        }
