    {
      "type": "codeBlock",
      "content": [
        {
          "type": "text",
          "text": "// Построение суффиксного массива (prefix-doubling) и LCP (Касаи)\n// Важно: добавьте к строке уникальный минимальный символ, например '$', которого нет в исходной строке.\n\nfunction buildSuffixArray(s) {\n  const n = s.length;\n  const sa = Array.from({ length: n }, (_, i) => i);\n  // Ранги по символам (используем кодпоинты; для ASCII/UTF-16 достаточно codePointAt)\n  let rank = Array.from(s, ch => ch.codePointAt(0));\n  let tmp = new Array(n).fill(0);\n\n  for (let k = 1; k < n; k <<= 1) {\n    sa.sort((i, j) => {\n      if (rank[i] !== rank[j]) return rank[i] - rank[j];\n      const ri = i + k < n ? rank[i + k] : -1;\n      const rj = j + k < n ? rank[j + k] : -1;\n      return ri - rj;\n    });\n\n    tmp[sa[0]] = 0;\n    for (let i = 1; i < n; i++) {\n      const a = sa[i - 1];\n      const b = sa[i];\n      const same = rank[a] === rank[b]\n        && (a + k < n ? rank[a + k] : -1) === (b + k < n ? rank[b + k] : -1);\n      tmp[b] = tmp[a] + (same ? 0 : 1);\n    }\n    for (let i = 0; i < n; i++) rank[i] = tmp[i];\n    if (rank[sa[n - 1]] === n - 1) break; // все ранги уникальны\n  }\n  return sa;\n}\n\nfunction buildLCP(s, sa) {\n  const n = s.length;\n  const rank = new Array(n);\n  for (let i = 0; i < n; i++) rank[sa[i]] = i;\n  const lcp = new Array(n).fill(0);\n  let k = 0;\n  for (let i = 0; i < n; i++) {\n    const r = rank[i];\n    if (r === 0) { k = 0; continue; }\n    const j = sa[r - 1];\n    while (i + k < n && j + k < n && s[i + k] === s[j + k]) k++;\n    lcp[r] = k;\n    if (k > 0) k--;\n  }\n  return lcp;\n}\n\n// Бинарный поиск подстроки P в S по SA\nfunction findOccurrences(s, sa, pat) {\n  const n = s.length;\n  const m = pat.length;\n\n  const cmpLower = (idx) => {\n    // сравниваем первые m символов\n    const sub = s.slice(idx, idx + m);\n    if (sub === pat) return 0;\n    return sub < pat ? -1 : 1; // лексикографическое сравнение строк JS\n  };\n\n  // нижняя граница (первое место, где суффикс >= pat-префиксу)\n  let lo = 0, hi = n;\n  while (lo < hi) {\n    const mid = (lo + hi) >> 1;\n    const c = cmpLower(sa[mid]);\n    if (c >= 0) hi = mid; else lo = mid + 1;\n  }\n  const start = lo;\n\n  // верхняя граница (первое место, где суффикс > pat-префиксу)\n  const cmpUpper = (idx) => {\n    const sub = s.slice(idx, idx + m);\n    return sub <= pat ? -1 : 1;\n  };\n  lo = 0; hi = n;\n  while (lo < hi) {\n    const mid = (lo + hi) >> 1;\n    const c = cmpUpper(sa[mid]);\n    if (c <= 0) lo = mid + 1; else hi = mid;\n  }\n  const end = lo;\n\n  const res = [];\n  for (let i = start; i < end; i++) res.push(sa[i]);\n  // Часто удобно вернуть отсортированные по позиции вхождения индексы\n  return res.sort((a, b) => a - b);\n}\n\n// Демонстрация\nconst s = \"banana$\"; // '$' не встречается в строке и минимален\nconst sa = buildSuffixArray(s);\nconst lcp = buildLCP(s, sa);\nconsole.log(\"SA:\", sa);           // [6, 5, 3, 1, 0, 4, 2]\nconsole.log(\"LCP:\", lcp);         // [0, 0, 1, 3, 0, 0, 2]\nconsole.log(findOccurrences(s, sa, \"ana\")); // [1, 3]"
        }
